inputs.command:
node - <<'NODE'
const options = {
  A: {strength:500, density:2.7, cost:16},
  B: {strength:900, density:4.4, cost:26},
  C: {strength:716, density:1.8, cost:40},
};
const s = Object.values(options).map(o=>o.strength);
const d = Object.values(options).map(o=>o.density);
const c = Object.values(options).map(o=>o.cost);
const min = a=>Math.min(...a), max=a=>Math.max(...a);
const sr=[min(s),max(s)], dr=[min(d),max(d)], cr=[min(c),max(c)];
for (const [k,o] of Object.entries(options)) {
  const strength=(o.strength-sr[0])/(sr[1]-sr[0]);
  const mass=(dr[1]-o.density)/(dr[1]-dr[0]);
  const cost=(cr[1]-o.cost)/(cr[1]-cr[0]);
  const total = strength*0.4 + mass*0.3 + cost*0.2;
  console.log(k, {strength, mass, cost, total});
}
NODE

